  onExternalFileProcessed?: () => void;
}

const CategorizeTab: React.FC<Props> = ({ onResultsChange, currentResults, externalFile, onExternalFileProcessed }) => {
  const [file, setFile] = useState<File | null>(null);
  const [workbook, setWorkbook] = useState<any>(null);
  const [config, setConfig] = useState<FileConfig>({
    sheetName: '',
    columnName: 'A',
    startRow: 2,
    hasHeader: true
  });
  const [processing, setProcessing] = useState<ProcessingState>({
    total: 0,
    processed: 0,
    results: [],
    isProcessing: false,
    error: null
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handle external file dropped via global listener
  useEffect(() => {
    if (externalFile) {
      processFile(externalFile);
      if (onExternalFileProcessed) onExternalFileProcessed();
    }
  }, [externalFile]);

  const processFile = async (uploadedFile: File) => {
    try {
      const wb = await parseExcelFile(uploadedFile);
      setWorkbook(wb);
      setFile(uploadedFile);
      setConfig({
        ...config,
        sheetName: wb.SheetNames[0] || ''
      });
      setProcessing(prev => ({ ...prev, error: null }));
    } catch (err) {
      setProcessing(prev => ({ ...prev, error: "Failed to parse Excel file. Please ensure it's a valid .xlsx file." }));
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = e.target.files?.[0];
    if (uploadedFile) {
      processFile(uploadedFile);
    }
  };

  const handleStartCategorization = async () => {
    if (!workbook || !config.sheetName) return;

    const itemsToProcess = extractItems(workbook, config);
    if (itemsToProcess.length === 0) {
      setProcessing(prev => ({ ...prev, error: "No items found in the selected sheet/column." }));
      return;
    }

    setProcessing({
      total: itemsToProcess.length,
      processed: 0,
      results: [],
      isProcessing: true,
      error: null
    });

    try {
      const finalResults = await categorizeItemsInBatches(itemsToProcess, (newResult) => {
        setProcessing(prev => ({
          ...prev,
          processed: prev.processed + 1,
          results: [...prev.results, newResult]
        }));
      });

      onResultsChange(finalResults);
      setProcessing(prev => ({ ...prev, isProcessing: false }));
    } catch (err) {
      setProcessing(prev => ({ 
        ...prev, 
        isProcessing: false, 
        error: "Categorization interrupted. Some items may have failed." 
      }));
    }
  };

  const downloadJson = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(currentResults, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href",     dataStr);
    downloadAnchorNode.setAttribute("download", "categorized_items.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  // UI Helpers
  const sheets = workbook?.SheetNames || [];
  const columns = ["A", "B", "C", "D", "E", "F", "G", "H", "I", "J", "K", "L", "M", "N", "O"];

  return (
    <div className="space-y-6">
      {!file ? (
        <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center transition-all hover:border-blue-300">
          <div className="mx-auto w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mb-4">
            <Upload size={32} />
          </div>
          <h2 className="text-xl font-semibold text-slate-800">Upload your inventory file</h2>
          <p className="text-slate-500 mt-2 max-w-sm mx-auto">
            Drop an Excel (.xlsx) file anywhere or click to browse. We'll handle the categorization for you.
